import './App.css';
import SearchBar from './components/SearchBar';
import ErrorMessage from './components/ErrorMessage';
import WeatherCard from './components/WeatherCard';
import Loader from './components/Loader';
import { useEffect, useState } from 'react';

const App = () => {
  const [city, setCity] = useState('');
  const [tcity, setTcity] = useState('');

  const [temperature, setTemperature] = useState('');
  const [wind, setWind] = useState('');
  const [humidity, setHumidity] = useState('');
  const [feelsLike, setFeelsLike] = useState('');
  const [condition, setCondition] = useState('');
  const [icon, setIcon] = useState('');
  const [aqi, setAQI] = useState('');

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const API_KEY = "9639c7cedda74131876100024262504"; //  API key

  const fetchWeather = async (cityName) => {
    try {
      setLoading(true);
      setError('');

      const res = await fetch(
        `https://api.weatherapi.com/v1/current.json?key=${API_KEY}&q=${cityName}&aqi=yes`
      );

      const data = await res.json();

      if (data.error) {
        setError("City not found");
        return;
      }

      // Destructuring
      const {
        location: { name },
        current: {
          temp_c,
          feelslike_c,
          humidity,
          wind_kph,
          condition: { text, icon },
          air_quality
        }
      } = data;

      setTcity(name);
      setTemperature(`Temperature: ${temp_c}°C`);
      setFeelsLike(`Feels Like: ${feelslike_c}°C`);
      setWind(`Wind: ${wind_kph} km/h`);
      setHumidity(`Humidity: ${humidity}%`);
      setCondition(text);
      setIcon(icon);
      setAQI(`AQI: ${air_quality["us-epa-index"]}`);

    } catch (err) {
      setError("Failed to fetch weather");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchWeather("Visakhapatnam");
  }, []);

  const checkWeather = () => {
    if (!city) {
      setError("Enter city name");
      return;
    }
    fetchWeather(city.trim());
    setCity('');
  };

  return (
    <div className="screen">
      <div className="main">
        <h1>Weather App</h1>

        <SearchBar
          city={city}
          setCity={setCity}
          onSearch={checkWeather}
        />

        {loading && <Loader />}
        {error && <ErrorMessage message={error} />}
        {!tcity && !loading && !error && (
          <p style={{ marginTop: "20px" }}>
          🔍 Enter a city to check weather
        </p>
           )}

        {tcity && !loading && (
          <WeatherCard
            city={tcity}
            icon={icon}
            temperature={temperature}
            feelsLike={feelsLike}
            condition={condition}
            wind={wind}
            humidity={humidity}
            aqi={aqi}
          />
        )}
      </div>
    </div>
  );
};

export default App;
